import{_ as t,o as s,c as n,a4 as e}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"能量动量综合套路","description":"","frontmatter":{},"headers":[],"relativePath":"physics/routine-energy.md","filePath":"physics/routine-energy.md"}'),l={name:"physics/routine-energy.md"};function p(i,a,r,d,c,o){return s(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="能量动量综合套路" tabindex="-1">能量动量综合套路 <a class="header-anchor" href="#能量动量综合套路" aria-label="Permalink to &quot;能量动量综合套路&quot;">​</a></h1><p><strong>模型编号</strong>: 20<br><strong>难度</strong>: ⭐⭐⭐⭐⭐<br><strong>核心</strong>: 多过程分析 + 能量动量工具选择</p><hr><h2 id="模型识别" tabindex="-1">模型识别 <a class="header-anchor" href="#模型识别" aria-label="Permalink to &quot;模型识别&quot;">​</a></h2><p><strong>关键词</strong>: 多过程、碰撞、滑动、能量转化、动量守恒</p><p><strong>常见情境</strong>:</p><ul><li>碰撞后滑上木板/曲面</li><li>弹簧连接+碰撞</li><li>爆炸后多物体运动</li><li>多次碰撞问题</li></ul><hr><h2 id="核心工具选择" tabindex="-1">核心工具选择 <a class="header-anchor" href="#核心工具选择" aria-label="Permalink to &quot;核心工具选择&quot;">​</a></h2><h3 id="什么时候用能量-什么时候用动量" tabindex="-1">什么时候用能量？什么时候用动量？ <a class="header-anchor" href="#什么时候用能量-什么时候用动量" aria-label="Permalink to &quot;什么时候用能量？什么时候用动量？&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">问题特征</th><th style="text-align:center;">用能量</th><th style="text-align:center;">用动量</th><th style="text-align:center;">两者都用</th></tr></thead><tbody><tr><td style="text-align:center;">涉及位移/高度</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">涉及时间</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">碰撞过程</td><td style="text-align:center;">✅（弹性）</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:center;">求速度大小</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">求共同速度</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:center;">求热量/做功</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">多物体相互作用</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;"></td></tr></tbody></table><h3 id="核心方程" tabindex="-1">核心方程 <a class="header-anchor" href="#核心方程" aria-label="Permalink to &quot;核心方程&quot;">​</a></h3><p><strong>能量守恒（系统）</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E初 = E末 + Q（热量）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>或：减少的能量 = 增加的能量</span></span></code></pre></div><p><strong>动量守恒（系统）</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>m₁v₁ + m₂v₂ = m₁v₁&#39; + m₂v₂&#39;（矢量式）</span></span></code></pre></div><p><strong>动能定理（单个物体）</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>W合 = ΔEk</span></span></code></pre></div><hr><h2 id="多过程分析步骤" tabindex="-1">多过程分析步骤 <a class="header-anchor" href="#多过程分析步骤" aria-label="Permalink to &quot;多过程分析步骤&quot;">​</a></h2><h3 id="步骤1-划分过程" tabindex="-1">步骤1：划分过程 <a class="header-anchor" href="#步骤1-划分过程" aria-label="Permalink to &quot;步骤1：划分过程&quot;">​</a></h3><p>按<strong>时间顺序</strong>或<strong>空间位置</strong>划分阶段：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>例：物块A撞B，B滑上木板C</span></span>
<span class="line"><span></span></span>
<span class="line"><span>过程1：A与B碰撞</span></span>
<span class="line"><span>过程2：B在C上滑动至共速</span></span></code></pre></div><h3 id="步骤2-每个过程选工具" tabindex="-1">步骤2：每个过程选工具 <a class="header-anchor" href="#步骤2-每个过程选工具" aria-label="Permalink to &quot;步骤2：每个过程选工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">过程类型</th><th style="text-align:center;">推荐工具</th><th style="text-align:left;">原因</th></tr></thead><tbody><tr><td style="text-align:center;">碰撞（短暂）</td><td style="text-align:center;">动量守恒</td><td style="text-align:left;">内力大，忽略外力</td></tr><tr><td style="text-align:center;">滑动（有摩擦）</td><td style="text-align:center;">能量守恒+动量守恒</td><td style="text-align:left;">有热量产生</td></tr><tr><td style="text-align:center;">弹簧作用</td><td style="text-align:center;">能量守恒+动量守恒</td><td style="text-align:left;">弹力是内力</td></tr><tr><td style="text-align:center;">圆周运动</td><td style="text-align:center;">能量守恒+牛顿定律</td><td style="text-align:left;">涉及向心力</td></tr></tbody></table><h3 id="步骤3-找衔接点" tabindex="-1">步骤3：找衔接点 <a class="header-anchor" href="#步骤3-找衔接点" aria-label="Permalink to &quot;步骤3：找衔接点&quot;">​</a></h3><p><strong>关键原则</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前段末态 = 后段初态</span></span>
<span class="line"><span></span></span>
<span class="line"><span>即：前段的末速度 = 后段的初速度</span></span>
<span class="line"><span>     前段的末位置 = 后段的初位置</span></span></code></pre></div><h3 id="步骤4-联立求解" tabindex="-1">步骤4：联立求解 <a class="header-anchor" href="#步骤4-联立求解" aria-label="Permalink to &quot;步骤4：联立求解&quot;">​</a></h3><p><strong>列方程策略</strong>：</p><ul><li>有几个未知量，列几个独立方程</li><li>动量守恒（矢量）可分解为x、y两个方向</li><li>能量守恒是标量，只有一个方程</li></ul><hr><h2 id="典型问题类型" tabindex="-1">典型问题类型 <a class="header-anchor" href="#典型问题类型" aria-label="Permalink to &quot;典型问题类型&quot;">​</a></h2><h3 id="类型1-碰撞-滑动-板块" tabindex="-1">类型1：碰撞+滑动（板块） <a class="header-anchor" href="#类型1-碰撞-滑动-板块" aria-label="Permalink to &quot;类型1：碰撞+滑动（板块）&quot;">​</a></h3><p><strong>问题</strong>: A以v₀撞静止B，B滑上静止木板C，求最终速度及热量</p><p><strong>解法</strong>:</p><p><strong>过程1：A与B碰撞</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>动量守恒：m_A v₀ = m_A v_A + m_B v_B</span></span>
<span class="line"><span>若弹性：½m_A v₀² = ½m_A v_A² + ½m_B v_B²</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解得v_A、v_B（v_B为B滑上C的初速度）</span></span></code></pre></div><p><strong>过程2：B在C上滑动</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>动量守恒：m_B v_B = (m_B + m_C)v共</span></span>
<span class="line"><span>能量守恒：½m_B v_B² = ½(m_B+m_C)v共² + Q</span></span>
<span class="line"><span>其中 Q = f·s相对 = μmg·s相对</span></span>
<span class="line"><span></span></span>
<span class="line"><span>可求v共和滑动距离s相对</span></span></code></pre></div><h3 id="类型2-弹簧-碰撞" tabindex="-1">类型2：弹簧+碰撞 <a class="header-anchor" href="#类型2-弹簧-碰撞" aria-label="Permalink to &quot;类型2：弹簧+碰撞&quot;">​</a></h3><p><strong>问题</strong>: A以v₀撞向连有弹簧的静止B，求弹簧最大压缩量</p><p><strong>解法</strong>:</p><p><strong>关键点</strong>：弹簧最大压缩时，A和B速度相同（相对速度为0）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>动量守恒：m_A v₀ = (m_A + m_B)v共</span></span>
<span class="line"><span>→ v共 = m_A v₀/(m_A + m_B)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>能量守恒：</span></span>
<span class="line"><span>½m_A v₀² = ½(m_A+m_B)v共² + Ep弹max</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解得Ep弹max = ½m_A v₀² - ½(m_A+m_B)[m_A v₀/(m_A+m_B)]²</span></span>
<span class="line"><span>           = ½·m_A m_B v₀²/(m_A+m_B)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最大压缩：x_max = √(2Ep弹max/k)</span></span></code></pre></div><h3 id="类型3-爆炸-反冲-平抛" tabindex="-1">类型3：爆炸/反冲+平抛 <a class="header-anchor" href="#类型3-爆炸-反冲-平抛" aria-label="Permalink to &quot;类型3：爆炸/反冲+平抛&quot;">​</a></h3><p><strong>问题</strong>: 炮弹在高h处水平爆炸成两块，求落地点距离</p><p><strong>解法</strong>:</p><p><strong>过程1：爆炸（瞬间）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>水平动量守恒：</span></span>
<span class="line"><span>Mv₀ = m₁v₁ + m₂v₂</span></span>
<span class="line"><span></span></span>
<span class="line"><span>爆炸能量：化学能→动能（能量增加）</span></span></code></pre></div><p><strong>过程2：平抛（各自）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>时间：t = √(2h/g)（相同）</span></span>
<span class="line"><span>水平位移：x₁ = v₁t，x₂ = v₂t</span></span>
<span class="line"><span>落点距离：Δx = |x₁ - x₂| = |v₁ - v₂|t</span></span></code></pre></div><hr><h2 id="套路总结图" tabindex="-1">套路总结图 <a class="header-anchor" href="#套路总结图" aria-label="Permalink to &quot;套路总结图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>能量动量综合</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 读题，画出过程图</span></span>
<span class="line"><span>    │       几个物体？几个阶段？</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 划分过程</span></span>
<span class="line"><span>    │       按时间顺序：碰撞→滑动→圆周...</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 每个过程选工具</span></span>
<span class="line"><span>    │       碰撞→动量守恒</span></span>
<span class="line"><span>    │       滑动→能量+动量</span></span>
<span class="line"><span>    │       弹簧→能量+动量</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 列方程</span></span>
<span class="line"><span>    │       动量守恒（矢量）</span></span>
<span class="line"><span>    │       能量守恒（标量）</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ 找衔接点</span></span>
<span class="line"><span>    │       前段末态=后段初态</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └──→ 联立求解</span></span>
<span class="line"><span>            代数运算/解方程组</span></span></code></pre></div><hr><h2 id="常见陷阱" tabindex="-1">常见陷阱 <a class="header-anchor" href="#常见陷阱" aria-label="Permalink to &quot;常见陷阱&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">陷阱</th><th style="text-align:left;">正确做法</th></tr></thead><tbody><tr><td style="text-align:left;">碰撞过程用能量守恒（非弹性）</td><td style="text-align:left;">非弹性碰撞机械能不守恒，只能用动量守恒</td></tr><tr><td style="text-align:left;">忘记热量计算</td><td style="text-align:left;">有摩擦时，动能损失=热量Q=f·s相对</td></tr><tr><td style="text-align:left;">动量守恒方向搞错</td><td style="text-align:left;">矢量式，设正方向，注意正负号</td></tr><tr><td style="text-align:left;">混淆系统和单体</td><td style="text-align:left;">动量守恒对系统，动能定理对单体</td></tr><tr><td style="text-align:left;">弹簧最大压缩条件错</td><td style="text-align:left;">共速时压缩最大，不是速度为零</td></tr></tbody></table><hr><h2 id="快速检查清单" tabindex="-1">快速检查清单 <a class="header-anchor" href="#快速检查清单" aria-label="Permalink to &quot;快速检查清单&quot;">​</a></h2><ul><li>[ ] 正确划分了过程阶段</li><li>[ ] 每个过程选对了工具（能量/动量）</li><li>[ ] 动量守恒方程设了正方向</li><li>[ ] 能量守恒包含了所有能量形式（含热量）</li><li>[ ] 衔接点速度/位置传递正确</li><li>[ ] 未知量个数=独立方程个数</li></ul><hr><p><em>配套速查</em>: 速查卡 → 模型20<br><em>详细推导</em>: 【高一高二用】新课学习/详解/05-能量动量详解.md</p>`,63)])])}const b=t(l,[["render",p]]);export{g as __pageData,b as default};
